import stylesText from './activity-detail-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { formatMacro } from '../../../utils/format-macro.js';

const styles = cssStyleSheet(stylesText);
import type { Activity } from '@motivation/shared';
import { activityIcon } from '../health-utils.js';

const SOURCE_ICONS: Record<string, string> = {
    manual: '✏️',
    strava: '🟧',
    calendar: '📅',
    // Story 250: Health Connect ingest — orange square for Strava-recorded, green heart for Google Fit.
    health_connect_strava: '🟧',
    health_connect_android_fitness: '💚',
};

const template = document.createElement('template');
template.innerHTML = `
    <div class="detail-card">
        <div class="card-left">
            <div class="type-icon" id="type-icon"></div>
        </div>
        <div class="card-body">
            <div class="card-title" id="title"></div>
            <div class="card-meta" id="meta"></div>
        </div>
        <div class="card-right">
            <span class="source-badge" id="source-badge" title=""></span>
        </div>
    </div>
`;

export class ActivityDetailCard extends HTMLElement {
    private _activity: Activity | null = null;
    private _estimatedBurnKcal: number | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    set activity(val: Activity) {
        this._activity = val;
        this.render();
    }

    /**
     * Story 258: MET-estimated burn, shown with a `~` prefix when the row has
     * no recorded `calories_burned`. A recorded value always wins.
     */
    set estimatedBurnKcal(val: number | null) {
        this._estimatedBurnKcal = val;
        this.render();
    }

    private formatDuration(minutes?: number): string {
        if (!minutes) return '';
        if (minutes >= 60) {
            const h = Math.floor(minutes / 60);
            const m = minutes % 60;
            return m > 0 ? `${h}h ${m}min` : `${h}h`;
        }
        return `${minutes} min`;
    }

    private render() {
        const a = this._activity;
        if (!a) return;

        const shadow = this.shadowRoot!;

        shadow.getElementById('type-icon')!.textContent = activityIcon(a.type);
        shadow.getElementById('title')!.textContent = a.title;

        // Build meta line: start time · duration · calories · description
        const parts: string[] = [];
        const start = startTimeLabel(a.metadata);
        if (start) parts.push(start);
        const dur = this.formatDuration(a.duration_minutes);
        if (dur) parts.push(dur);
        if (a.calories_burned) {
            parts.push(`${formatMacro(a.calories_burned)} kcal`);
        } else if (this._estimatedBurnKcal != null && this._estimatedBurnKcal > 0) {
            parts.push(`~${formatMacro(this._estimatedBurnKcal)} kcal`);
        }
        if (a.description) parts.push(a.description);
        shadow.getElementById('meta')!.textContent = parts.join(' · ');

        const sourceEl = shadow.getElementById('source-badge')!;
        sourceEl.textContent = SOURCE_ICONS[a.source] ?? '❓';
        sourceEl.title = a.source.charAt(0).toUpperCase() + a.source.slice(1);
    }
}

/**
 * HH:MM start-of-activity label from the metadata JSON, when the sync path
 * recorded one (HC: `start`; Strava: `start_date_local`). Manual rows have
 * none and render without a time. Times render as recorded (already local
 * for Strava; HC instants project through the device zone).
 */
function startTimeLabel(metadata?: string): string | null {
    if (!metadata) return null;
    try {
        const parsed = JSON.parse(metadata) as { start?: string; start_date_local?: string };
        const raw = parsed.start_date_local ?? parsed.start;
        if (!raw) return null;
        const match = raw.match(/T(\d{2}:\d{2})/);
        return match ? match[1] : null;
    } catch {
        return null;
    }
}

customElements.define('activity-detail-card', ActivityDetailCard);
