const LONG_PRESS_MS = 500;
const LONG_PRESS_MOVE_TOLERANCE_PX = 10;

/** Story 258: a slot whose kcal exceed this share of the budget gets the ⚠. */
const SLOT_WARN_BUDGET_FRACTION = 0.5;

/**
 * Chronological sort key for a consumption entry (story 260): the eaten-at
 * instant when stamped, otherwise `created_at` (SQLite `datetime('now')` is
 * UTC with a space) normalized to the same ISO-instant shape so one string
 * compare orders mixed lists.
 */
function entrySortInstant(entry: ConsumptionEntry): string {
    return entry.consumed_at ?? `${entry.created_at.replace(' ', 'T')}Z`;
}

/** Days-since figures per "deliberate" activity type (story 258, 3c widget). */
export interface LastActivityDays {
    weight_training: number | null;
    running: number | null;
    cycling: number | null;
}

export class HealthDayDetail extends HTMLElement {
    private _dateStr: string = '';
    private _activities: Activity[] = [];
    private _nutrition: ConsumptionEntry[] = [];
    private _foodItemsById: Map<string, FoodItem> = new Map();
    private _mealsById: Map<string, Meal> = new Map();
    private _summary: DailyNutritionSummary | null = null;
    private _dayBurn: ActivityBurn | null = null;
    private _burnByActivityId: Map<string, ActivityBurn> = new Map();
    private _steps: number | null = null;
    private _selectionMode = false;
    private _selectedIds = new Set<string>();
    private unsubscribeTargets: (() => void) | null = null;

    connectedCallback(): void {
        // The hero bars, slot ⚠ and steps goal all scale against the targets,
        // which resolve asynchronously at boot (and can be edited from the
        // week widget) — re-render the target-dependent pieces when they land.
        this.unsubscribeTargets = healthTargetsService.onChange(() => {
            this.renderSummary();
            this.renderNutrition();
            this.renderSteps();
        });
    }

    disconnectedCallback(): void {
        this.unsubscribeTargets?.();
        this.unsubscribeTargets = null;
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        shadow.getElementById('prev-btn')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            const prevDay = Temporal.PlainDate.from(this._dateStr).subtract({ days: 1 }).toString();
            navigate(`/health/day/${prevDay}`, { history: 'replace' });
        });

        shadow.getElementById('next-btn')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            const nextDay = Temporal.PlainDate.from(this._dateStr).add({ days: 1 }).toString();
            navigate(`/health/day/${nextDay}`, { history: 'replace' });
        });

        shadow.getElementById('add-workout-btn')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            this.dispatchEvent(createAddWorkoutEvent({ date: this._dateStr }));
        });

        // Story 173/258: the header 💬 chip jumps to this day's briefing —
        // the note keyed by day D is the one written on the morning of D
        // looking ahead to it.
        shadow.getElementById('coach-chip')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            navigate(`/health/coaching/${encodeURIComponent(this._dateStr)}`);
        });

        // Story 258: Activity | Nutrition tabs. Transient UI state — not URL.
        shadow.getElementById('tab-activity')!.addEventListener('click', () => this.setActiveTab('activity'));
        shadow.getElementById('tab-nutrition')!.addEventListener('click', () => this.setActiveTab('nutrition'));

        shadow.getElementById('cancel-selection-btn')!.addEventListener('click', () => {
            this.exitSelectionMode();
        });

        shadow.getElementById('save-as-meal-btn')!.addEventListener('click', () => {
            if (this._selectedIds.size === 0) return;
            // Preserve user-visible order: filter the rendered nutrition list by selection.
            const ordered = this._nutrition
                .filter((e) => this._selectedIds.has(e.id))
                .map((e) => e.id);
            navigate(`/health/meals?fromSelection=${ordered.map(encodeURIComponent).join(',')}`);
        });

        const mealSections = shadow.getElementById('meal-sections')!;
        for (const meal of MEAL_TYPES) {
            const section = document.createElement('day-meal-section');
            section.setAttribute('meal-type', meal);
            section.dataset.mealType = meal;
            const emptyState = document.createElement('div');
            emptyState.className = 'empty-state';
            emptyState.dataset.role = 'empty';
            emptyState.textContent = 'Nothing logged yet.';
            section.appendChild(emptyState);
            mealSections.appendChild(section);
        }

        // Listen on the host rather than the shadow root: `ShadowRoot`'s typed
        // event map only knows `slotchange`, so the typed CustomEvent listener
        // doesn't type-check against shadow.addEventListener. Same outcome at
        // runtime because `day-meal-section-add` bubbles + composed.
        this.addEventListener(HEALTH_EVENTS.DAY_MEAL_SECTION_ADD, (event: DayMealSectionAddEvent) => {
            if (!this._dateStr) return;
            this.dispatchEvent(createAddFoodEvent({ date: this._dateStr, meal: event.detail.meal }));
        });
    }

    set dateContext(val: string) {
        if (val !== this._dateStr) this.exitSelectionMode();
        this._dateStr = val;
        this.shadowRoot!.getElementById('day-title')!.textContent = val;
    }

    get dateContext(): string {
        return this._dateStr;
    }

    set activities(data: Activity[]) {
        this._activities = data;
        this.renderWorkouts();
    }

    // The Activity pane's ghost stubs (story 260) derive from nutrition data,
    // so nutrition-side setters re-render the workouts pane too.
    set nutrition(data: ConsumptionEntry[]) {
        this._nutrition = data;
        this.renderNutrition();
        this.renderSummary();
        this.renderWorkouts();
    }

    set foodItemsById(items: Map<string, FoodItem>) {
        this._foodItemsById = items;
        this.renderNutrition();
        this.renderWorkouts();
    }

    set mealsById(items: Map<string, Meal>) {
        this._mealsById = items;
        this.renderNutrition();
        this.renderWorkouts();
    }

    set summary(data: DailyNutritionSummary | null) {
        this._summary = data;
        this.renderSummary();
    }

    /** Day burn (real-or-estimated), story 258 — feeds the hero and the burn row. */
    set dayBurn(data: ActivityBurn | null) {
        this._dayBurn = data;
        this.renderSummary();
        this.renderDayBurnRow();
    }

    /** Per-activity burn for the workout cards' `~N kcal` fallback (story 258). */
    set burnByActivityId(data: Map<string, ActivityBurn>) {
        this._burnByActivityId = data;
        this.renderWorkouts();
    }

    /** Steps recorded for this day, or null when there is no row (story 258). */
    set steps(value: number | null) {
        this._steps = value;
        this.renderSteps();
    }

    private renderSteps(): void {
        const shadow = this.shadowRoot!;
        const row = shadow.getElementById('steps-row')!;
        if (this._steps === null) {
            row.hidden = true;
            return;
        }
        const goal = getHealthTargets().step_goal;
        shadow.getElementById('steps-fill')!.style.width = `${Math.min(this._steps / goal, 1) * 100}%`;
        shadow.getElementById('steps-label')!.textContent = `${formatSteps(this._steps)} / ${formatSteps(goal)}`;
        row.hidden = false;
    }

    /** "Time since" per deliberate activity type, relative to the viewed day. */
    set lastActivityDays(value: LastActivityDays) {
        const row = this.shadowRoot!.getElementById('since-row')!;
        row.replaceChildren();
        const entries: Array<[string, number | null]> = [
            ['🏋️', value.weight_training],
            ['🏃', value.running],
            ['🚴', value.cycling],
        ];
        for (const [icon, days] of entries) {
            const span = document.createElement('span');
            span.className = 'since-item';
            span.textContent = days === null ? `${icon} —` : days === 0 ? `${icon} today ✓` : `${icon} ${days}d ago`;
            row.appendChild(span);
        }
    }

    private setActiveTab(tab: 'activity' | 'nutrition'): void {
        const shadow = this.shadowRoot!;
        const activity = tab === 'activity';
        shadow.getElementById('activity-pane')!.hidden = !activity;
        shadow.getElementById('nutrition-pane')!.hidden = activity;
        shadow.getElementById('tab-activity')!.classList.toggle('is-active', activity);
        shadow.getElementById('tab-activity')!.setAttribute('aria-selected', String(activity));
        shadow.getElementById('tab-nutrition')!.classList.toggle('is-active', !activity);
        shadow.getElementById('tab-nutrition')!.setAttribute('aria-selected', String(!activity));
    }

    private renderDayBurnRow(): void {
        const shadow = this.shadowRoot!;
        const row = shadow.getElementById('day-burn-row')!;
        if (!this._dayBurn || this._dayBurn.kcal <= 0) {
            row.hidden = true;
            return;
        }
        shadow.getElementById('day-burn-total')!.textContent =
            `${this._dayBurn.estimated ? '~' : ''}${formatMacro(this._dayBurn.kcal)} kcal`;
        row.hidden = false;
    }

    showLoading() {
        const shadow = this.shadowRoot!;
        shadow.getElementById('loading')!.hidden = false;
        shadow.getElementById('content')!.hidden = true;
        shadow.getElementById('error')!.hidden = true;
    }

    hideLoading() {
        this.shadowRoot!.getElementById('loading')!.hidden = true;
    }

    showError(message: string) {
        const shadow = this.shadowRoot!;
        const el = shadow.getElementById('error')!;
        el.textContent = message;
        el.hidden = false;
        shadow.getElementById('loading')!.hidden = true;
    }

    showContent() {
        this.shadowRoot!.getElementById('content')!.hidden = false;
    }

    private renderSummary() {
        const shadow = this.shadowRoot!;
        let cal = 0, p = 0, c = 0, f = 0, fib = 0;

        if (this._summary) {
            cal = this._summary.total_calories;
            p = this._summary.total_protein_g;
            c = this._summary.total_carbs_g;
            f = this._summary.total_fat_g;
            fib = this._summary.total_fiber_g;
        } else if (this._nutrition.length > 0) {
            // Fallback aggregation if summary not provided yet
            cal = this._nutrition.reduce((s, e) => s + (e.calories ?? 0), 0);
            p = this._nutrition.reduce((s, e) => s + (e.protein_g ?? 0), 0);
            c = this._nutrition.reduce((s, e) => s + (e.carbs_g ?? 0), 0);
            f = this._nutrition.reduce((s, e) => s + (e.fat_g ?? 0), 0);
            fib = this._nutrition.reduce((s, e) => s + (e.fiber_g ?? 0), 0);
        }

        shadow.getElementById('total-cal')!.textContent = formatMacro(cal);
        shadow.getElementById('total-p')!.textContent = formatMacro(p);
        shadow.getElementById('total-c')!.textContent = formatMacro(c);
        shadow.getElementById('total-fat')!.textContent = formatMacro(f);
        shadow.getElementById('total-fib')!.textContent = formatMacro(fib);

        // Story 258 hero: burn credit stretches the allowance past the budget;
        // the tick marks the budget itself. Judged on net (eaten − burn).
        const targets = getHealthTargets();
        const budget = targets.calorie_budget_kcal;
        const burn = this._dayBurn?.kcal ?? 0;
        const burnPrefix = this._dayBurn?.estimated ? '~' : '';
        const net = cal - burn;

        const burnEl = shadow.getElementById('hero-burn')!;
        const netEl = shadow.getElementById('hero-net')!;
        if (burn > 0) {
            burnEl.textContent = `🔥 −${burnPrefix}${formatMacro(burn)}`;
            netEl.textContent = `net ${burnPrefix}${formatMacro(net)}`;
            burnEl.hidden = false;
            netEl.hidden = false;
        } else {
            burnEl.hidden = true;
            netEl.hidden = true;
        }

        const allowance = budget + burn;
        const scale = Math.max(cal, allowance, 1);
        shadow.getElementById('hero-kcal-fill')!.style.width = `${(cal / scale) * 100}%`;
        const credit = shadow.getElementById('hero-burn-credit')!;
        if (burn > 0) {
            credit.style.left = `${(budget / scale) * 100}%`;
            credit.style.width = `${(burn / scale) * 100}%`;
            credit.hidden = false;
        } else {
            credit.hidden = true;
        }
        shadow.getElementById('hero-budget-tick')!.style.left = `${(budget / scale) * 100}%`;
        const kcalLabel = shadow.getElementById('hero-kcal-label')!;
        const over = net - budget;
        kcalLabel.textContent = over > 0 ? `+${formatMacro(over)} over` : 'under ✓';
        kcalLabel.classList.toggle('is-over', over > 0);

        shadow.getElementById('hero-protein-fill')!.style.width =
            `${Math.min(p / targets.protein_target_g, 1) * 100}%`;
        shadow.getElementById('protein-target')!.textContent = formatMacro(targets.protein_target_g);
    }

    private renderWorkouts() {
        const container = this.shadowRoot!.getElementById('workouts-list')!;
        container.replaceChildren();
        if (this._activities.length === 0) {
            const emptyState = document.createElement('div');
            emptyState.className = 'empty-state';
            emptyState.textContent = 'No workouts logged.';
            container.appendChild(emptyState);
        }

        // Walks are Fit auto-detections, not the workouts this list is for
        // (story 254): several on one day fold into a collapsed <details>
        // group; the individual cards inside stay clickable. Real workouts
        // render first.
        const walks = this._activities.filter((a) => a.type === 'walking');
        const rest = this._activities.filter((a) => a.type !== 'walking');

        for (const act of rest) {
            container.appendChild(this.buildActivityCard(act));
        }

        if (walks.length === 1) {
            container.appendChild(this.buildActivityCard(walks[0]));
        } else if (walks.length > 1) {
            const group = document.createElement('details');
            group.className = 'walks-group';
            const summary = document.createElement('summary');
            const total = walks.reduce((sum, walk) => sum + (walk.duration_minutes ?? 0), 0);
            summary.textContent = `${activityIcon('walking')} ${walks.length} walks · ${formatDurationMinutes(total)}`;
            group.appendChild(summary);
            for (const act of walks) {
                group.appendChild(this.buildActivityCard(act));
            }
            container.appendChild(group);
        }

        // Story 260 (3b/3c wireframes): stamped meals ghost through into the
        // Activity feed, ordered by eaten-at time. Unstamped days add nothing.
        const stubs = this.buildMealStubs();
        if (stubs) container.appendChild(stubs);
    }

    /**
     * Cross-tab ghost stubs (story 260): one subdued row per stamped logged
     * meal (occurrence group) or stamped standalone entry, ordered by time.
     * Clicking one jumps to the Nutrition tab. Returns null when the day has
     * no stamped entries — no stubs, no container.
     */
    private buildMealStubs(): HTMLElement | null {
        const stamped = this._nutrition.filter((e) => e.consumed_at);
        if (stamped.length === 0) return null;

        const byOccurrence = new Map<string, ConsumptionEntry[]>();
        const singles: ConsumptionEntry[] = [];
        for (const entry of stamped) {
            if (entry.meal_occurrence_id) {
                const arr = byOccurrence.get(entry.meal_occurrence_id) ?? [];
                arr.push(entry);
                byOccurrence.set(entry.meal_occurrence_id, arr);
            } else {
                singles.push(entry);
            }
        }

        const items: Array<{ instant: string; name: string; kcal: number }> = [];
        for (const [, group] of byOccurrence) {
            const sourceMealId = group[0].source_meal_id;
            const meal = sourceMealId ? this._mealsById.get(sourceMealId) ?? null : null;
            items.push({
                instant: group.map((e) => e.consumed_at!).sort()[0],
                name: meal?.name ?? `${group[0].meal_type} meal`,
                kcal: group.reduce((s, e) => s + (e.calories ?? 0), 0),
            });
        }
        for (const entry of singles) {
            items.push({
                instant: entry.consumed_at!,
                name: this._foodItemsById.get(entry.food_item_id)?.display_name ?? 'Food',
                kcal: entry.calories ?? 0,
            });
        }
        items.sort((a, b) => a.instant.localeCompare(b.instant));

        const list = document.createElement('div');
        list.className = 'meal-stubs';
        for (const item of items) {
            const stub = document.createElement('button');
            stub.type = 'button';
            stub.className = 'meal-stub';
            const time = document.createElement('span');
            time.className = 'food-time';
            time.textContent = instantToHHMM(item.instant, getAppTimeZone());
            const name = document.createElement('span');
            name.className = 'meal-stub-name';
            name.textContent = `🍽 ${item.name}`;
            const kcal = document.createElement('span');
            kcal.className = 'meal-stub-kcal';
            kcal.textContent = `${formatMacro(item.kcal)} kcal`;
            stub.append(time, name, kcal);
            stub.addEventListener('click', () => this.setActiveTab('nutrition'));
            list.appendChild(stub);
        }
        return list;
    }

    private buildActivityCard(act: Activity): ActivityDetailCard {
        const card = document.createElement('activity-detail-card') as ActivityDetailCard;
        card.activity = act;
        // Story 258: MET estimate fallback for rows without recorded energy.
        const burn = this._burnByActivityId.get(act.id);
        card.estimatedBurnKcal = burn?.estimated ? burn.kcal : null;
        // Calendar activities are re-materialized live and have no DB row, so
        // editing/deleting them is meaningless — only manual + synced (strava /
        // health_connect) cards are clickable (the edit page then shows
        // source-appropriate affordances).
        if (act.source !== 'calendar') {
            card.style.cursor = 'pointer';
            card.addEventListener('click', () => {
                this.dispatchEvent(createEditWorkoutEvent({ activity: act }));
            });
        }
        return card;
    }

    private renderNutrition() {
        const shadow = this.shadowRoot!;
        for (const meal of MEAL_TYPES) {
            const section = shadow.querySelector(`day-meal-section[data-meal-type="${meal}"]`) as HTMLElement | null;
            if (!section) continue;
            section.replaceChildren();

            const entries = this._nutrition.filter(e =>
                e.meal_type && e.meal_type.toLowerCase() === meal.toLowerCase()
            );

            // Story 258: slot total in the divider header; a slot eating more
            // than half the budget gets the ⚠ treatment.
            const slotTotal = entries.reduce((s, e) => s + (e.calories ?? 0), 0);
            if (slotTotal > 0) {
                section.setAttribute('total-kcal', formatMacro(slotTotal));
                section.toggleAttribute('over', slotTotal > getHealthTargets().calorie_budget_kcal * SLOT_WARN_BUDGET_FRACTION);
            } else {
                section.removeAttribute('total-kcal');
                section.removeAttribute('over');
            }

            if (entries.length === 0) {
                const emptyState = document.createElement('div');
                emptyState.className = 'empty-state';
                emptyState.textContent = 'Nothing logged yet.';
                section.appendChild(emptyState);
                continue;
            }

            // Group by meal_occurrence_id so entries logged from a meal template
            // collapse under one header. Entries without an occurrence id render flat.
            const grouped = new Map<string, ConsumptionEntry[]>();
            const ungrouped: ConsumptionEntry[] = [];
            for (const entry of entries) {
                const occurrenceId = entry.meal_occurrence_id;
                if (occurrenceId) {
                    const arr = grouped.get(occurrenceId) ?? [];
                    arr.push(entry);
                    grouped.set(occurrenceId, arr);
                } else {
                    ungrouped.push(entry);
                }
            }

            // Story 260: chronological within the slot — stamped entries sort
            // by eaten-at; unstamped keep their created_at position (both keys
            // are normalized UTC instants, so plain string compare works). A
            // group sorts by its earliest entry.
            const units: Array<{ key: string; el: HTMLElement }> = [];
            for (const [, groupEntries] of grouped) {
                const key = groupEntries.map((e) => entrySortInstant(e)).sort()[0];
                units.push({ key, el: this.createMealGroup(groupEntries) });
            }
            for (const entry of ungrouped) {
                units.push({ key: entrySortInstant(entry), el: this.createFoodItem(entry) });
            }
            units.sort((a, b) => a.key.localeCompare(b.key));
            for (const unit of units) {
                section.appendChild(unit.el);
            }
        }
    }

    private createMealGroup(entries: ConsumptionEntry[]): HTMLElement {
        const sourceMealId = entries[0]?.source_meal_id ?? null;
        const meal = sourceMealId ? this._mealsById.get(sourceMealId) ?? null : null;
        const mealName = meal?.name ?? null;
        const totalCal = entries.reduce((s, e) => s + (e.calories ?? 0), 0);

        const details = document.createElement('details');
        details.className = 'meal-group';
        if (meal?.image_path) details.classList.add('meal-group--with-banner');

        const summary = document.createElement('summary');
        summary.className = 'meal-group-summary';

        // Banner: <img> with darkening gradient overlay (CSS) so name/kcal stay
        // legible on arbitrary photos. The <img> is non-interactive (pointer-
        // events:none in CSS) so clicks fall through to the <summary> toggle.
        // Story 127.
        if (meal?.image_path) {
            const banner = document.createElement('img');
            banner.className = 'meal-group-banner';
            banner.src = FilesService.variantUrl(meal.image_path, 'display.jpg');
            banner.alt = '';
            banner.setAttribute('loading', 'lazy');
            banner.setAttribute('decoding', 'async');
            summary.appendChild(banner);
        }

        // Story 260: a stamped group shows its eaten-at HH:MM in the header
        // (groups share one stamp — logMeal stamps every expanded entry alike).
        const stamped = entries.find((e) => e.consumed_at)?.consumed_at ?? null;
        if (stamped) {
            const groupTime = document.createElement('span');
            groupTime.className = 'food-time';
            groupTime.textContent = instantToHHMM(stamped, getAppTimeZone());
            summary.appendChild(groupTime);
        }

        const nameSpan = document.createElement('span');
        nameSpan.className = 'meal-group-name';
        nameSpan.textContent = mealName ?? 'Deleted meal';
        const countSpan = document.createElement('span');
        countSpan.className = 'meal-group-count';
        countSpan.textContent = `${entries.length} item${entries.length === 1 ? '' : 's'}`;
        const calSpan = document.createElement('span');
        calSpan.className = 'food-cals';
        calSpan.textContent = `${formatMacro(totalCal)} kcal`;
        summary.appendChild(nameSpan);
        summary.appendChild(countSpan);
        summary.appendChild(calSpan);

        // Only meals that still have a template (source_meal_id is non-null) get
        // an edit link. Deleted-meal groups stay browse-only.
        if (sourceMealId) {
            const editLink = document.createElement('a');
            editLink.className = 'meal-group-edit';
            editLink.href = `/health/meals?focus=${encodeURIComponent(sourceMealId)}`;
            editLink.textContent = 'Edit recipe →';
            // Stop the click from bubbling to <summary>; otherwise it toggles open/close.
            editLink.addEventListener('click', (e) => e.stopPropagation());
            summary.appendChild(editLink);
        }

        // Story 255: scale / move / delete the whole logged meal at once. The
        // menu is keyed on the shared meal_occurrence_id and works even for a
        // deleted-template group (grouping survives, only the name is lost). It
        // emits MEAL_GROUP_* events that bubble to the day screen.
        const occurrenceId = entries[0]?.meal_occurrence_id;
        if (occurrenceId) {
            const menu = document.createElement('meal-group-menu');
            menu.setAttribute('occurrence-id', occurrenceId);
            menu.setAttribute('meal-name', mealName ?? 'Logged meal');
            menu.setAttribute('total-cal', String(totalCal));
            menu.setAttribute('date', entries[0].date);
            menu.setAttribute('meal-type', entries[0].meal_type);
            summary.appendChild(menu);
        }

        details.appendChild(summary);

        for (const entry of entries) {
            details.appendChild(this.createFoodItem(entry));
        }
        return details;
    }

    private createFoodItem(entry: ConsumptionEntry): HTMLElement {
        const foodItem = this._foodItemsById.get(entry.food_item_id);
        const displayName = foodItem?.display_name ?? 'Unknown food';

        const item = document.createElement('div');
        item.className = 'food-item';
        item.dataset.entryId = entry.id;
        item.style.cursor = 'pointer';

        const checkbox = document.createElement('input');
        checkbox.type = 'checkbox';
        checkbox.className = 'food-select';
        checkbox.checked = this._selectedIds.has(entry.id);
        // Stop the checkbox from also triggering item-level click/long-press.
        checkbox.addEventListener('click', (e) => e.stopPropagation());
        checkbox.addEventListener('pointerdown', (e) => e.stopPropagation());
        checkbox.addEventListener('change', () => {
            if (checkbox.checked) this._selectedIds.add(entry.id);
            else this._selectedIds.delete(entry.id);
            this.refreshSelectionToolbar();
        });

        // Story 260: HH:MM spine label for stamped entries, projected through
        // the app zone. Unstamped rows keep an empty cell so the spine aligns.
        const time = document.createElement('span');
        time.className = 'food-time';
        time.textContent = entry.consumed_at ? instantToHHMM(entry.consumed_at, getAppTimeZone()) : '';

        const thumb = document.createElement('food-thumb');
        if (foodItem?.image_path) thumb.setAttribute('path', foodItem.image_path);
        thumb.setAttribute('alt', displayName);

        const name = document.createElement('span');
        name.className = 'food-name';
        name.textContent = displayName;

        const cals = document.createElement('span');
        cals.className = 'food-cals';
        cals.textContent = `${formatMacro(entry.calories ?? 0)} kcal`;

        const macros = document.createElement('div');
        macros.className = 'food-macros';
        const chip = (label: string, value: number, unit: string): HTMLSpanElement => {
            const s = document.createElement('span');
            s.className = 'food-macro';
            s.textContent = `${label}:${formatMacro(value)}${unit}`;
            return s;
        };
        macros.append(
            chip('P', entry.protein_g ?? 0, 'g'),
            chip('C', entry.carbs_g ?? 0, 'g'),
            chip('F', entry.fat_g ?? 0, 'g'),
            chip('Fb', entry.fiber_g ?? 0, 'g'),
            chip('Sugar', entry.sugar_g ?? 0, 'g'),
            chip('Na', entry.sodium_mg ?? 0, 'mg'),
        );

        item.append(checkbox, time, thumb, name, cals, macros);
        this.attachEntryInteractions(item, entry);
        return item;
    }

    private attachEntryInteractions(item: HTMLElement, entry: ConsumptionEntry): void {
        let longPressTimer: ReturnType<typeof setTimeout> | null = null;
        let startX = 0;
        let startY = 0;
        let longPressed = false;

        const cancelTimer = () => {
            if (longPressTimer) {
                clearTimeout(longPressTimer);
                longPressTimer = null;
            }
        };

        item.addEventListener('pointerdown', (e) => {
            longPressed = false;
            startX = e.clientX;
            startY = e.clientY;
            cancelTimer();
            longPressTimer = setTimeout(() => {
                longPressTimer = null;
                longPressed = true;
                this.enterSelectionMode(entry.id);
                if (typeof navigator.vibrate === 'function') navigator.vibrate(10);
            }, LONG_PRESS_MS);
        });

        item.addEventListener('pointermove', (e) => {
            if (!longPressTimer) return;
            if (Math.hypot(e.clientX - startX, e.clientY - startY) > LONG_PRESS_MOVE_TOLERANCE_PX) {
                cancelTimer();
            }
        });

        item.addEventListener('pointerup', cancelTimer);
        item.addEventListener('pointercancel', cancelTimer);
        item.addEventListener('pointerleave', cancelTimer);

        // Suppress the native context menu the browser fires for long-press —
        // it would compete with our selection-mode trigger.
        item.addEventListener('contextmenu', (e) => e.preventDefault());

        item.addEventListener('click', (e) => {
            if (longPressed) {
                longPressed = false;
                e.preventDefault();
                e.stopPropagation();
                return;
            }
            if (this._selectionMode) {
                this.toggleSelection(entry.id);
                return;
            }
            this.dispatchEvent(createEditFoodEvent({ entry }));
        });
    }

    private enterSelectionMode(seedEntryId: string): void {
        this._selectionMode = true;
        this._selectedIds.add(seedEntryId);
        this.classList.add('selection-mode');
        // Reflect checkbox state on the seeded row (it is already in the DOM).
        this.syncCheckboxes();
        this.refreshSelectionToolbar();
    }

    private exitSelectionMode(): void {
        if (!this._selectionMode && this._selectedIds.size === 0) return;
        this._selectionMode = false;
        this._selectedIds.clear();
        this.classList.remove('selection-mode');
        this.syncCheckboxes();
        this.refreshSelectionToolbar();
    }

    private toggleSelection(entryId: string): void {
        if (this._selectedIds.has(entryId)) this._selectedIds.delete(entryId);
        else this._selectedIds.add(entryId);
        this.syncCheckboxes();
        this.refreshSelectionToolbar();
    }

    private syncCheckboxes(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const items = shadow.querySelectorAll<HTMLElement>('.food-item[data-entry-id]');
        for (const item of items) {
            const id = item.dataset.entryId!;
            const cb = item.querySelector<HTMLInputElement>('.food-select');
            if (cb) cb.checked = this._selectedIds.has(id);
        }
    }

    private refreshSelectionToolbar(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const toolbar = shadow.getElementById('selection-toolbar')!;
        const count = shadow.getElementById('selection-count')!;
        const saveBtn = shadow.getElementById('save-as-meal-btn') as HTMLButtonElement;
        toolbar.hidden = !this._selectionMode;
        const n = this._selectedIds.size;
        count.textContent = `${n} selected`;
        saveBtn.disabled = n === 0;
    }

}

customElements.define('health-day-detail', HealthDayDetail);
