import stylesText from './meal-group-menu.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { formatMacro } from '../../../../utils/format-macro.js';
import { MEAL_TYPES } from '@motivation/shared';
import type { MealType } from '@motivation/shared';
import {
    createMealGroupScaleEvent,
    createMealGroupMoveEvent,
    createMealGroupDeleteEvent,
} from '../../health-events.js';

const styles = cssStyleSheet(stylesText);

// Presentational action sheet for one logged meal (a meal_occurrence_id group),
// mounted by health-day-detail inside each meal-group <summary>. It gathers a
// scale factor / move target / delete confirmation and dispatches a typed
// MEAL_GROUP_* event; the day screen owns the mutation + refresh. Story 255.
const template = document.createElement('template');
template.innerHTML = `
    <button type="button" class="trigger" aria-label="Meal actions" title="Meal actions">⋯</button>
    <dialog class="sheet">
        <header class="sheet-header">
            <span class="sheet-title"></span>
            <span class="sheet-kcal"></span>
        </header>

        <div class="panel" data-panel="menu">
            <button type="button" class="action" data-action="scale"><span class="ico">⚖</span> Scale portion</button>
            <button type="button" class="action" data-action="move"><span class="ico">↦</span> Move to day / meal</button>
            <button type="button" class="action action--danger" data-action="delete"><span class="ico">🗑</span> Delete from day</button>
            <button type="button" class="link-btn" data-action="close">Cancel</button>
        </div>

        <div class="panel" data-panel="scale" hidden>
            <div class="chips">
                <button type="button" class="chip" data-factor="0.5">×0.5</button>
                <button type="button" class="chip" data-factor="1.5">×1.5</button>
                <button type="button" class="chip" data-factor="2">×2</button>
                <label class="chip chip--custom">×<input type="number" class="factor-input" min="0.1" step="0.1" inputmode="decimal" value="1"></label>
            </div>
            <div class="preview"><span class="preview-old"></span><span class="arrow"> → </span><span class="preview-new"></span></div>
            <div class="panel-actions">
                <button type="button" class="link-btn" data-action="back">Back</button>
                <button type="button" class="btn-primary" data-action="apply-scale">Apply</button>
            </div>
        </div>

        <div class="panel" data-panel="move" hidden>
            <label class="field"><span>Day</span><input type="date" class="move-date"></label>
            <label class="field"><span>Meal</span>
                <select class="move-meal">
                    ${MEAL_TYPES.map((m) => `<option value="${m}">${m}</option>`).join('')}
                </select>
            </label>
            <div class="panel-actions">
                <button type="button" class="link-btn" data-action="back">Back</button>
                <button type="button" class="btn-primary" data-action="apply-move">Move</button>
            </div>
        </div>

        <div class="panel" data-panel="delete" hidden>
            <p class="confirm-text"></p>
            <div class="panel-actions">
                <button type="button" class="link-btn" data-action="back">Back</button>
                <button type="button" class="btn-danger" data-action="apply-delete">Delete</button>
            </div>
        </div>
    </dialog>
`;

export class MealGroupMenu extends HTMLElement {
    private readonly sheet: HTMLDialogElement;
    private readonly factorInput: HTMLInputElement;
    private readonly moveDate: HTMLInputElement;
    private readonly moveMeal: HTMLSelectElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        this.sheet = shadow.querySelector('dialog')!;
        this.factorInput = shadow.querySelector('.factor-input')!;
        this.moveDate = shadow.querySelector('.move-date')!;
        this.moveMeal = shadow.querySelector('.move-meal')!;

        const trigger = shadow.querySelector<HTMLButtonElement>('.trigger')!;
        trigger.addEventListener('click', (e) => {
            // Keep the click off the parent <summary>, which would toggle the
            // <details> open/closed (mirrors the edit-link in health-day-detail).
            e.stopPropagation();
            this.open();
        });

        // A backdrop click lands on the <dialog> element itself → close.
        this.sheet.addEventListener('click', (e) => {
            if (e.target === this.sheet) this.sheet.close();
        });

        shadow.addEventListener('click', (e) => {
            const btn = (e.target as HTMLElement).closest<HTMLElement>('[data-action]');
            if (!btn) return;
            this.handleAction(btn.dataset.action!);
        });

        for (const chip of shadow.querySelectorAll<HTMLButtonElement>('.chip[data-factor]')) {
            chip.addEventListener('click', () => {
                this.factorInput.value = chip.dataset.factor!;
                this.updatePreview();
            });
        }
        this.factorInput.addEventListener('input', () => this.updatePreview());
    }

    private get occurrenceId(): string { return this.getAttribute('occurrence-id') ?? ''; }
    private get totalCal(): number { return Number(this.getAttribute('total-cal') ?? '0'); }

    private open(): void {
        this.showPanel('menu');
        const shadow = this.shadowRoot!;
        shadow.querySelector('.sheet-title')!.textContent = this.getAttribute('meal-name') || 'Logged meal';
        shadow.querySelector('.sheet-kcal')!.textContent = `${formatMacro(this.totalCal)} kcal`;
        shadow.querySelector('.confirm-text')!.textContent =
            `Delete “${this.getAttribute('meal-name') || 'this meal'}” and all its items?`;
        // Reset the sub-forms to the group's current state each time it opens.
        this.factorInput.value = '1';
        this.updatePreview();
        this.moveDate.value = this.getAttribute('date') ?? '';
        this.moveMeal.value = this.getAttribute('meal-type') ?? MEAL_TYPES[0];
        this.sheet.showModal();
    }

    private showPanel(name: string): void {
        for (const panel of this.shadowRoot!.querySelectorAll<HTMLElement>('.panel')) {
            panel.hidden = panel.dataset.panel !== name;
        }
    }

    private readFactor(): number | null {
        const factor = parseFloat(this.factorInput.value);
        return Number.isFinite(factor) && factor > 0 ? factor : null;
    }

    private updatePreview(): void {
        const factor = this.readFactor();
        const shadow = this.shadowRoot!;
        shadow.querySelector('.preview-old')!.textContent = `${formatMacro(this.totalCal)} kcal`;
        shadow.querySelector('.preview-new')!.textContent =
            factor === null ? '—' : `${formatMacro(this.totalCal * factor)} kcal`;
        shadow.querySelector<HTMLButtonElement>('[data-action="apply-scale"]')!.disabled = factor === null;
    }

    private handleAction(action: string): void {
        switch (action) {
            case 'scale': this.showPanel('scale'); break;
            case 'move': this.showPanel('move'); break;
            case 'delete': this.showPanel('delete'); break;
            case 'back': this.showPanel('menu'); break;
            case 'close': this.sheet.close(); break;
            case 'apply-scale': {
                const factor = this.readFactor();
                if (factor === null) return;
                this.dispatchEvent(createMealGroupScaleEvent({ occurrence_id: this.occurrenceId, factor }));
                this.sheet.close();
                break;
            }
            case 'apply-move': {
                const date = this.moveDate.value;
                const meal_type = this.moveMeal.value as MealType;
                if (!date) return;
                this.dispatchEvent(createMealGroupMoveEvent({ occurrence_id: this.occurrenceId, date, meal_type }));
                this.sheet.close();
                break;
            }
            case 'apply-delete':
                this.dispatchEvent(createMealGroupDeleteEvent({ occurrence_id: this.occurrenceId }));
                this.sheet.close();
                break;
        }
    }
}

if (!customElements.get('meal-group-menu')) {
    customElements.define('meal-group-menu', MealGroupMenu);
}
