/** Weight lookback so MET burn estimates have a plausible body weight. */
const WEIGHT_LOOKBACK_DAYS = 90;
/** How far back the "time since 🏋️/🏃/🚴" row looks (story 258). */
const TIME_SINCE_LOOKBACK_DAYS = 60;

/**
 * Whole days between the viewed day and the last activity of `type` on or
 * before it (0 = that same day), or null when none in the lookback window.
 */
function daysSinceLastOfType(activities: Activity[], type: string, day: Temporal.PlainDate): number | null {
    let last: string | null = null;
    for (const activity of activities) {
        if (activity.type !== type || activity.date > day.toString()) continue;
        if (last === null || activity.date > last) last = activity.date;
    }
    return last === null ? null : day.since(Temporal.PlainDate.from(last)).total({ unit: 'days' });
}

