export class HealthDayScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private detail: HealthDayDetail | null = null;
    private quickLog: HTMLElement | null = null;
    private loadSequence = 0;
    private dateValue = '';
    private moreMenuOpen = false;
    private dialogHost: HTMLElement | null = null;
    private readonly log = createComponentLogger('health-day-screen');

    set date(value: string) {
        this.dateValue = value;
    }

    setLoading(): void {
        this.detail?.showLoading();
    }

    setError(err: unknown): void {
        if (err instanceof Error) {
            this.detail?.showError(err.stack ?? err.message);
        } else {
            this.detail?.showError(String(err));
        }
    }

    clearStatus(): void {
        this.detail?.hideLoading();
    }

    connectedCallback(): void {
        if (!this.initialized) {
            this.initialized = true;

            const page = buildSectionPage(this, 'Health', 'health', '/health');

            // Story 173/258: the way into the coaching note is the 💬 chip in
            // the day-detail header (the briefing keyed by day D is the one
            // written on the morning of D looking ahead to it).
            this.detail = document.createElement('health-day-detail') as HealthDayDetail;
            this.detail.dateContext = this.dateValue;
            this.detail.showLoading();
            page.content.appendChild(this.detail);

            // Story 258: the quick-log bar logs to the *viewed* date; the `›`
            // opens the same more-actions menu as the dashboard.
            this.quickLog = document.createElement('quick-log-bar');
            this.quickLog.className = 'day-quick-log';
            this.quickLog.setAttribute('date', this.dateValue);
            page.content.appendChild(this.quickLog);

            this.dialogHost = document.createElement('div');
            page.content.appendChild(this.dialogHost);
            this.dialogHost.appendChild(moreMenuTemplate.content.cloneNode(true));
            this.dialogHost.appendChild(addActivityTemplate.content.cloneNode(true));

            this.wireDetail();
            this.wireMoreMenu();
            this.wireAddDialog();
        }

        if (this.detail) {
            this.detail.dateContext = this.dateValue;
        }
        this.quickLog?.setAttribute('date', this.dateValue);
        void this.loadData();
    }

    private wireDetail(): void {
        if (!this.detail) return;
        this.detail.addEventListener(HEALTH_EVENTS.ADD_WORKOUT, (event: AddWorkoutEvent) => {
            this.openManualAddDialog(event.detail.date);
        });

        this.detail.addEventListener(HEALTH_EVENTS.ADD_FOOD, (event: AddFoodEvent) => {
            navigate(`/health/food-entry/${encodeURIComponent(event.detail.date)}/${encodeURIComponent(event.detail.meal)}`);
        });

        this.detail.addEventListener(HEALTH_EVENTS.EDIT_FOOD, (event: EditFoodEvent) => {
            navigate(`/health/nutrition/${encodeURIComponent(event.detail.entry.id)}`);
        });

        this.detail.addEventListener(HEALTH_EVENTS.EDIT_WORKOUT, (event: EditWorkoutEvent) => {
            navigate(`/health/activity/${encodeURIComponent(event.detail.activity.id)}`);
        });

        // Story 255: whole logged-meal (occurrence group) actions.
        this.detail.addEventListener(HEALTH_EVENTS.MEAL_GROUP_SCALE, (event: MealGroupScaleEvent) => {
            void this.mutateMeal(() => HealthService.scaleMealOccurrence(event.detail.occurrence_id, event.detail.factor));
        });
        this.detail.addEventListener(HEALTH_EVENTS.MEAL_GROUP_MOVE, (event: MealGroupMoveEvent) => {
            void this.mutateMeal(() => HealthService.moveMealOccurrence(event.detail.occurrence_id, {
                date: event.detail.date,
                meal_type: event.detail.meal_type,
                // Story 260: preserve the eaten-at wall-clock in the zone this
                // client renders when the group moves to another date.
                time_zone: getAppTimeZone(),
            }));
        });
        this.detail.addEventListener(HEALTH_EVENTS.MEAL_GROUP_DELETE, (event: MealGroupDeleteEvent) => {
            void this.mutateMeal(() => HealthService.deleteMealOccurrence(event.detail.occurrence_id));
        });
    }

    // The `›` menu — same options as the dashboard's, except Log Activity
    // pre-fills the *viewed* date instead of today.
    private wireMoreMenu(): void {
        this.addEventListener(HEALTH_EVENTS.QUICK_LOG_MORE, () => this.toggleMoreMenu());

        this.querySelector<HTMLButtonElement>('#more-food')!.addEventListener('click', () => {
            this.closeMoreMenu();
            // The generic add flow (no slot preset) — the barcode + AI
            // estimate entry point; the bar's slot buttons cover the
            // viewed-date slotted case.
            navigate('/health/food-entry');
        });
        this.querySelector<HTMLButtonElement>('#more-activity')!.addEventListener('click', () => {
            this.closeMoreMenu();
            this.openManualAddDialog(this.dateValue);
        });
        this.querySelector<HTMLButtonElement>('#more-template')!.addEventListener('click', () => {
            this.closeMoreMenu();
            navigate('/health/workout-templates');
        });
        this.querySelector<HTMLButtonElement>('#more-weight')!.addEventListener('click', () => {
            this.closeMoreMenu();
            navigate('/health/weight');
        });
        this.querySelector<HTMLButtonElement>('#more-meals')!.addEventListener('click', () => {
            this.closeMoreMenu();
            navigate('/health/meals');
        });
    }

    private toggleMoreMenu(): void {
        this.moreMenuOpen = !this.moreMenuOpen;
        this.querySelector<HTMLElement>('#more-menu')!.hidden = !this.moreMenuOpen;
    }

    private closeMoreMenu(): void {
        this.moreMenuOpen = false;
        this.querySelector<HTMLElement>('#more-menu')!.hidden = true;
    }

    // Run a logged-meal mutation, then re-render — both inside one safeExec so a
    // failed mutation surfaces its raw error instead of being papered over by the
    // follow-up refresh (safeExec swallows on error and does not rethrow).
    private async mutateMeal(op: () => Promise<unknown>): Promise<void> {
        return safeExec(this, this.log, async () => {
            await op();
            await this.fetchAndRender();
        }, { errorMessage: 'Failed to update meal' });
    }

    private wireAddDialog(): void {
        const dialog = this.querySelector<HTMLDialogElement>('#activity-dialog');
        const form = this.querySelector<HTMLFormElement>('#activity-form');
        if (!dialog || !form) return;

        dialog.addEventListener('close', () => {
            try {
                if (dialog.returnValue !== 'save') return;

                const data = Object.fromEntries(new FormData(form)) as Record<string, string>;
                if (!data.title || !data.date) return;

                void this.saveManualActivity({
                    title: data.title,
                    type: data.type,
                    date: data.date,
                    duration_minutes: data.duration ? parseInt(data.duration, 10) : undefined,
                });
            } finally {
                form.reset();
            }
        });
    }

    private async saveManualActivity(data: {
        title: string;
        type: string;
        date: string;
        duration_minutes?: number;
    }): Promise<void> {
        return safeExec(this, this.log, async () => {
            // Land on the hub (story 181) — attach a workout/cardio there rather
            // than branching on type here.
            await createActivityAndOpenHub(data);
        });
    }

    private openManualAddDialog(date: string): void {
        const dialog = this.querySelector<HTMLDialogElement>('#activity-dialog');
        const dateInput = this.querySelector<HTMLInputElement>('#act-date');
        if (dialog && dateInput) {
            dateInput.value = date;
            dialog.showModal();
        }
    }

    private async loadData(): Promise<void> {
        if (!this.detail) return;
        return safeExec(this, this.log, () => this.fetchAndRender(), { errorMessage: `Failed to load detail for ${this.dateValue}` });
    }

    // The raw fetch + render, without status handling — it throws on failure so
    // the caller's safeExec surfaces it. Shared by loadData() and mutateMeal().
    private async fetchAndRender(): Promise<void> {
        if (!this.detail) return;

        const currentLoad = ++this.loadSequence;
        this.detail.dateContext = this.dateValue;

        const day = Temporal.PlainDate.from(this.dateValue);
        const [activities, nutrition, daySteps, weights, lookback] = await Promise.all([
            HealthService.fetchActivitiesByDate(this.dateValue),
            HealthService.fetchConsumptionByDate(this.dateValue),
            // Story 258: steps + weights (MET-estimate body weight) + a
            // lookback window for the "time since 🏋️/🏃/🚴" widget row.
            HealthService.fetchDailySteps(this.dateValue, this.dateValue),
            HealthService.fetchWeightByDateRange(day.subtract({ days: WEIGHT_LOOKBACK_DAYS }).toString(), this.dateValue),
            HealthService.fetchMeaningfulActivitiesByDateRange(day.subtract({ days: TIME_SINCE_LOOKBACK_DAYS }).toString(), this.dateValue),
        ]);

        // Story 116: ConsumptionEntry references food_item_id; the day detail
        // needs the food items to render names. Fetch in parallel — typically
        // a handful per day, so a few extra round trips are fine.
        const uniqueFoodIds = [...new Set(nutrition.map((e) => e.food_item_id))];
        // Story 161: a genuine error on one item must not fail the whole day —
        // mirror the meals path below. The missing id drops out of the map and
        // the renderer falls back to "Unknown food" for that entry.
        const foodItems = await Promise.all(uniqueFoodIds.map((id) => HealthService.fetchFoodItem(id).catch(() => null)));
        const foodItemsById = new Map(foodItems.filter((it) => it !== null).map((it) => [it!.id, it!] as const));

        // Story 077: resolve source_meal_id → name for entries logged from a meal template.
        const uniqueMealIds = [...new Set(nutrition.map((e) => e.source_meal_id).filter((id): id is string => Boolean(id)))];
        const meals = await Promise.all(uniqueMealIds.map((id) => HealthService.fetchMeal(id).catch(() => null)));
        const mealsById = new Map(meals.filter((m) => m !== null).map((m) => [m!.id, m!] as const));

        if (currentLoad !== this.loadSequence || !this.detail) return;

        // Story 258: burn (real-or-estimated) per activity and for the day.
        const weightKg = weightKgOnDate(weights, this.dateValue);
        const burnByActivityId = new Map(
            activities.flatMap((activity) => {
                const burn = activityBurnKcal(activity, weightKg);
                return burn ? [[activity.id, burn] as const] : [];
            }),
        );
        this.detail.burnByActivityId = burnByActivityId;
        this.detail.dayBurn = dayBurnKcal(activities, weightKg);
        this.detail.steps = daySteps.find((s) => s.date === this.dateValue)?.steps ?? null;
        this.detail.lastActivityDays = {
            weight_training: daysSinceLastOfType(lookback, 'weight_training', day),
            running: daysSinceLastOfType(lookback, 'running', day),
            cycling: daysSinceLastOfType(lookback, 'cycling', day),
        };

        this.detail.activities = activities;
        this.detail.foodItemsById = foodItemsById;
        this.detail.mealsById = mealsById;
        this.detail.nutrition = nutrition;
        this.detail.showContent();
    }

}

customElements.define('health-day-screen', HealthDayScreen);
